class Solution(object):
    def count(self, num1, num2, min_sum, max_sum):
        """
        :type num1: str
        :type num2: str
        :type min_sum: int
        :type max_sum: int
        :rtype: int
        """
        MOD = 10**9 + 7

        def count_up_to(num_str, min_s, max_s):
            """Count integers <= num_str with digit_sum in [min_s, max_s]"""
            memo = {}
            n = len(num_str)

            def dp(pos, tight, digit_sum):
                if digit_sum > max_s:
                    return 0

                if pos == n:
                    return 1 if min_s <= digit_sum <= max_s else 0

                if (pos, tight, digit_sum) in memo:
                    return memo[(pos, tight, digit_sum)]

                limit = int(num_str[pos]) if tight else 9
                result = 0

                for digit in range(limit + 1):
                    new_tight = tight and (digit == limit)
                    result = (result + dp(pos + 1, new_tight, digit_sum + digit)) % MOD

                memo[(pos, tight, digit_sum)] = result
                return result

            return dp(0, True, 0)

        # Answer = count(num2) - count(num1 - 1)
        count_num2 = count_up_to(num2, min_sum, max_sum)

        # Decrement num1
        num1_int = int(num1)
        if num1_int > 0:
            num1_minus_1 = str(num1_int - 1)
        else:
            num1_minus_1 = "0"

        count_num1_minus_1 = count_up_to(num1_minus_1, min_sum, max_sum) if num1_int > 0 else 0

        return (count_num2 - count_num1_minus_1 + MOD) % MOD
